import React from 'react';
import { ChevronRight } from 'lucide-react';

interface MockOrder {
  id: string;
  customerName: string;
  garmentsCount: number;
  status: string;
  dueDate: string;
  total: string;
}

const mockOrders: MockOrder[] = [
  { id: 'ORD-1001', customerName: 'Rahul Sharma', garmentsCount: 5, status: 'Ready', dueDate: 'May 20, 2024', total: '₹1,250' },
  { id: 'ORD-1002', customerName: 'Priya Mehta', garmentsCount: 3, status: 'In Cleaning', dueDate: 'May 21, 2024', total: '₹850' },
  { id: 'ORD-1003', customerName: 'Arjun Verma', garmentsCount: 7, status: 'Received', dueDate: 'May 22, 2024', total: '₹1,750' },
  { id: 'ORD-1004', customerName: 'Neha Kapoor', garmentsCount: 2, status: 'Ready', dueDate: 'May 20, 2024', total: '₹600' },
  { id: 'ORD-1005', customerName: 'Vikram Singh', garmentsCount: 4, status: 'Delivered', dueDate: 'May 18, 2024', total: '₹1,200' },
];

const getStatusClass = (status: string) => {
  switch (status) {
    case 'Ready': return 'ready';
    case 'In Cleaning': return 'in_cleaning';
    case 'Received': return 'received';
    case 'Delivered': return 'delivered';
    default: return 'received';
  }
};

const RecentOrders: React.FC = () => {
  return (
    <div className="card">
      <div className="card-header">
        <div className="card-title">Recent Orders</div>
        <a href="#" className="card-action">View all orders &gt;</a>
      </div>

      <table className="orders-table">
        <thead>
          <tr>
            <th>Order ID</th>
            <th>Customer</th>
            <th>Garments</th>
            <th>Status</th>
            <th>Due Date</th>
            <th>Total</th>
            <th></th>
          </tr>
        </thead>
        <tbody>
          {mockOrders.map((order) => (
            <tr key={order.id}>
              <td style={{ fontWeight: 500 }}>{order.id}</td>
              <td>{order.customerName}</td>
              <td>{order.garmentsCount} items</td>
              <td>
                <span className={`status-badge ${getStatusClass(order.status)}`}>
                  {order.status}
                </span>
              </td>
              <td>{order.dueDate}</td>
              <td>{order.total}</td>
              <td><ChevronRight size={16} color="#94a3b8" /></td>
            </tr>
          ))}
        </tbody>
      </table>

      <div style={{ textAlign: 'center', marginTop: '16px' }}>
        <a href="#" className="card-action">View all orders</a>
      </div>
    </div>
  );
};

export default RecentOrders;
